11.     /// Extension methods to add <see cref="ArmClient"/> client to clients builder.
12.     /// </summary>
13.     public static class ArmClientBuilderExtensions
14.     {
15.         /// <summary>
16.         /// Registers an <see cref="ArmClient"/> instance with the provided <paramref name="defaultSubscription"/>
17.         /// </summary>
18.         public static IAzureClientBuilder<ArmClient, ArmClientOptions> AddArmClient<TBuilder>(this TBuilder builder, string defaultSubscription)
19.             where TBuilder : IAzureClientFactoryBuilderWithCredential
20.         {
21.             return builder.RegisterClientFactory<ArmClient, ArmClientOptions>((options, cred) => new ArmClient(cred, defaultSubscription, options));
22.         }
23. 
24.         /// <summary>
25.         /// Registers an <see cref="ArmClient"/> instance with connection options loaded from the provided <paramref name="configuration"/> instance.
26.         /// </summary>
27.         public static IAzureClientBuilder<ArmClient, ArmClientOptions> AddArmClient<TBuilder, TConfiguration>(this TBuilder builder, TConfiguration configuration)
28.             where TBuilder : IAzureClientFactoryBuilderWithConfiguration<TConfiguration>
29.         {
30.             return builder.RegisterClientFactory<ArmClient, ArmClientOptions>(configuration);
31.         }
32.     }
33. }
