/// <summary>
/// Sets the api versions from an Azure Stack profile.
/// </summary>
public void SetApiVersionsFromProfile(AzureStackProfile profile)
{
    var assembly = typeof(ArmClientOptions).Assembly;
    using (Stream stream = assembly.GetManifestResourceStream(profile.GetManifestName()))
    {
        var data = BinaryData.FromStream(stream);
        using var document = JsonDocument.Parse(data);
        var root = document.RootElement;
        if (!root.TryGetProperty("resource-manager", out JsonElement armProfile))
        {
            return;
        }
        foreach (var namespaceProperty in armProfile.EnumerateObject())
        {
            var namespaceName = namespaceProperty.Name;
            foreach (var apiVersionProperty in namespaceProperty.Value.EnumerateObject())
            {
                var apiVersion = apiVersionProperty.Name;
                foreach (var resourceTypeItem in apiVersionProperty.Value.EnumerateArray())
